package ru.memearena.media.api;
import jakarta.validation.constraints.NotNull; import org.springframework.core.io.InputStreamResource; import org.springframework.http.*; import org.springframework.security.core.annotation.AuthenticationPrincipal; import org.springframework.validation.annotation.Validated; import org.springframework.web.bind.annotation.*; import org.springframework.web.multipart.MultipartFile; import ru.memearena.media.application.MediaService; import ru.memearena.ratelimit.RateLimiterService; import ru.memearena.security.AuthenticatedUserPrincipal; import java.util.UUID;
@Validated @RestController @RequestMapping("/api/v1/media") public class MediaController { private final MediaService service; private final RateLimiterService limits; public MediaController(MediaService service,RateLimiterService limits){this.service=service;this.limits=limits;} @PostMapping(value="/images",consumes=MediaType.MULTIPART_FORM_DATA_VALUE) public ResponseEntity<MediaUploadResponse> upload(@AuthenticationPrincipal AuthenticatedUserPrincipal p,@Deprecated @RequestParam(required=false) UUID userId,@RequestPart MultipartFile file){limits.check("upload-hour",p.userId().toString(),10,3600); limits.check("upload-day",p.userId().toString(),30,86400); var r=service.upload(p.userId(),file); return ResponseEntity.status(HttpStatus.CREATED).body(MediaUploadResponse.of(r.asset(),r.duplicateDetected()));} @GetMapping("/{mediaId}/content") public ResponseEntity<InputStreamResource> content(@PathVariable UUID mediaId,@AuthenticationPrincipal AuthenticatedUserPrincipal p,@RequestHeader(value="If-None-Match",required=false) String inm){var c=service.content(mediaId,p==null?null:p.userId()); if(c.etag().equals(inm)) return ResponseEntity.status(HttpStatus.NOT_MODIFIED).eTag(c.etag()).build(); return ResponseEntity.ok().contentType(MediaType.parseMediaType(c.contentType())).contentLength(c.sizeBytes()).eTag(c.etag()).cacheControl(CacheControl.maxAge(365,java.util.concurrent.TimeUnit.DAYS).cachePublic()).body(new InputStreamResource(c.stream()));} }
